SourceCode.Declaration:
/// <summary>
/// Number sequence for Elevator receipt - Abhinav
/// </summary>
internal final class ETGElevatorReceiptNumberNumSeq extends NumberSeqApplicationModule
{
}

Method.Source:
protected void loadModule()
{
    NumberSeqDatatype datatype = NumberSeqDatatype::construct();

    datatype.parmDatatypeId(extendedTypeNum(ETGElevatorReceiptNumber));
    datatype.parmReferenceHelp(literalStr("Unique key used for elevator receipt number."));
    datatype.parmReferenceLabel(literalStr("Elevator receipt number"));
    datatype.parmWizardIsContinuous(true);
    datatype.parmWizardIsManual(NoYes::No);
    datatype.parmWizardFetchAheadQty(10);
    datatype.parmWizardIsChangeDownAllowed(NoYes::No);
    datatype.parmWizardIsChangeUpAllowed(NoYes::No);
    datatype.parmSortField(1);

    datatype.addParameterType(NumberSeqParameterType::DataArea, true, false);
    this.create(datatype);
}
